/**
 * Error Codes & Messages
 * Centralized error definitions with HTTP status codes and recovery suggestions
 */

export enum ErrorCode {
  // Authentication & Authorization (1000-1099)
  AUTH_INVALID_CREDENTIALS = 'ERR_1001',
  AUTH_TOKEN_EXPIRED = 'ERR_1002',
  AUTH_TOKEN_INVALID = 'ERR_1003',
  AUTH_UNAUTHORIZED = 'ERR_1004',
  AUTH_FORBIDDEN = 'ERR_1005',
  AUTH_USER_NOT_FOUND = 'ERR_1006',
  AUTH_EMAIL_EXISTS = 'ERR_1007',
  AUTH_USERNAME_EXISTS = 'ERR_1008',

  // Validation Errors (2000-2099)
  VALIDATION_FAILED = 'ERR_2001',
  VALIDATION_INVALID_INPUT = 'ERR_2002',
  VALIDATION_MISSING_FIELD = 'ERR_2003',
  VALIDATION_INVALID_FORMAT = 'ERR_2004',

  // Resource Errors (3000-3099)
  RESOURCE_NOT_FOUND = 'ERR_3001',
  RESOURCE_ALREADY_EXISTS = 'ERR_3002',
  RESOURCE_CONFLICT = 'ERR_3003',
  RESOURCE_DELETED = 'ERR_3004',

  // Database Errors (4000-4099)
  DATABASE_ERROR = 'ERR_4001',
  DATABASE_CONNECTION_FAILED = 'ERR_4002',
  DATABASE_QUERY_FAILED = 'ERR_4003',
  DATABASE_TRANSACTION_FAILED = 'ERR_4004',

  // External Service Errors (5000-5099)
  EXTERNAL_SERVICE_ERROR = 'ERR_5001',
  EXTERNAL_SERVICE_TIMEOUT = 'ERR_5002',
  EXTERNAL_SERVICE_UNAVAILABLE = 'ERR_5003',
  SCRAPER_ERROR = 'ERR_5004',

  // File Upload Errors (6000-6099)
  FILE_UPLOAD_FAILED = 'ERR_6001',
  FILE_TOO_LARGE = 'ERR_6002',
  FILE_INVALID_TYPE = 'ERR_6003',
  FILE_NOT_FOUND = 'ERR_6004',

  // Rate Limiting & Quota (7000-7099)
  RATE_LIMIT_EXCEEDED = 'ERR_7001',
  QUOTA_EXCEEDED = 'ERR_7002',

  // Server Errors (8000-8099)
  INTERNAL_SERVER_ERROR = 'ERR_8001',
  SERVICE_UNAVAILABLE = 'ERR_8002',
  NOT_IMPLEMENTED = 'ERR_8003',

  // Business Logic Errors (9000-9099)
  BUSINESS_LOGIC_ERROR = 'ERR_9001',
  INVALID_STATE = 'ERR_9002',
  OPERATION_NOT_ALLOWED = 'ERR_9003',
}

export interface ErrorDefinition {
  code: ErrorCode;
  message: string;
  statusCode: number;
  recoveryTip: string;
}

export const ERROR_DEFINITIONS: Record<ErrorCode, ErrorDefinition> = {
  // Authentication & Authorization
  [ErrorCode.AUTH_INVALID_CREDENTIALS]: {
    code: ErrorCode.AUTH_INVALID_CREDENTIALS,
    message: 'Email atau password tidak valid',
    statusCode: 401,
