  },
  [ErrorCode.AUTH_TOKEN_EXPIRED]: {
    code: ErrorCode.AUTH_TOKEN_EXPIRED,
    message: 'Token telah kadaluarsa',
    statusCode: 401,
    recoveryTip: 'Silakan login kembali untuk mendapatkan token baru.',
  },
  [ErrorCode.AUTH_TOKEN_INVALID]: {
    code: ErrorCode.AUTH_TOKEN_INVALID,
    message: 'Token tidak valid',
    statusCode: 401,
    recoveryTip: 'Token Anda tidak valid atau rusak. Silakan login kembali.',
  },
  [ErrorCode.AUTH_UNAUTHORIZED]: {
    code: ErrorCode.AUTH_UNAUTHORIZED,
    message: 'Anda tidak memiliki otorisasi untuk mengakses resource ini',
    statusCode: 401,
    recoveryTip: 'Pastikan Anda sudah login dengan akun yang tepat.',
  },
  [ErrorCode.AUTH_FORBIDDEN]: {
    code: ErrorCode.AUTH_FORBIDDEN,
    message: 'Akses ditolak',
    statusCode: 403,
    recoveryTip: 'Anda tidak memiliki izin untuk mengakses resource ini. Hubungi administrator jika Anda merasa ini adalah kesalahan.',
  },
  [ErrorCode.AUTH_USER_NOT_FOUND]: {
    code: ErrorCode.AUTH_USER_NOT_FOUND,
    message: 'User tidak ditemukan',
    statusCode: 404,
    recoveryTip: 'User yang Anda cari tidak ada dalam sistem. Periksa kembali informasi yang Anda masukkan.',
  },
  [ErrorCode.AUTH_EMAIL_EXISTS]: {
    code: ErrorCode.AUTH_EMAIL_EXISTS,
    message: 'Email sudah terdaftar',
    statusCode: 409,
    recoveryTip: 'Email ini sudah digunakan. Gunakan email lain atau gunakan fitur login jika sudah memiliki akun.',
