  [ErrorCode.AUTH_USERNAME_EXISTS]: {
    code: ErrorCode.AUTH_USERNAME_EXISTS,
    message: 'Username sudah digunakan',
    statusCode: 409,
    recoveryTip: 'Username ini sudah digunakan. Pilih username lain.',
  },

  // Validation Errors
  [ErrorCode.VALIDATION_FAILED]: {
    code: ErrorCode.VALIDATION_FAILED,
    message: 'Validasi data gagal',
    statusCode: 400,
    recoveryTip: 'Periksa kembali data yang Anda kirimkan dan pastikan sesuai dengan format yang diharapkan.',
