    code: ErrorCode.DATABASE_TRANSACTION_FAILED,
    message: 'Transaksi database gagal',
    statusCode: 500,
    recoveryTip: 'Transaksi tidak dapat diselesaikan. Silakan coba lagi.',
  },

  // External Service Errors
  [ErrorCode.EXTERNAL_SERVICE_ERROR]: {
    code: ErrorCode.EXTERNAL_SERVICE_ERROR,
    message: 'Layanan eksternal mengalami kesalahan',
    statusCode: 502,
    recoveryTip: 'Layanan eksternal sedang mengalami masalah. Silakan coba lagi nanti.',
  },
  [ErrorCode.EXTERNAL_SERVICE_TIMEOUT]: {
    code: ErrorCode.EXTERNAL_SERVICE_TIMEOUT,
    message: 'Layanan eksternal timeout',
    statusCode: 504,
    recoveryTip: 'Layanan eksternal tidak merespons tepat waktu. Silakan coba lagi.',
  },
  [ErrorCode.EXTERNAL_SERVICE_UNAVAILABLE]: {
    code: ErrorCode.EXTERNAL_SERVICE_UNAVAILABLE,
    message: 'Layanan eksternal tidak tersedia',
    statusCode: 503,
    recoveryTip: 'Layanan eksternal sedang tidak tersedia. Silakan coba lagi nanti.',
  },
  [ErrorCode.SCRAPER_ERROR]: {
    code: ErrorCode.SCRAPER_ERROR,
    message: 'Scraper mengalami kesalahan',
    statusCode: 500,
    recoveryTip: 'Proses scraping gagal. Silakan coba lagi atau hubungi administrator.',
  },

  // File Upload Errors
  [ErrorCode.FILE_UPLOAD_FAILED]: {
