    code: ErrorCode.QUOTA_EXCEEDED,
    message: 'Quota telah terlampaui',
    statusCode: 429,
    recoveryTip: 'Anda telah mencapai batas quota. Silakan upgrade akun atau tunggu periode berikutnya.',
  },

  // Server Errors
  [ErrorCode.INTERNAL_SERVER_ERROR]: {
    code: ErrorCode.INTERNAL_SERVER_ERROR,
    message: 'Terjadi kesalahan pada server',
    statusCode: 500,
    recoveryTip: 'Terjadi kesalahan teknis yang tidak terduga. Tim support telah diberitahu. Silakan coba lagi nanti.',
  },
  [ErrorCode.SERVICE_UNAVAILABLE]: {
    code: ErrorCode.SERVICE_UNAVAILABLE,
    message: 'Layanan tidak tersedia',
    statusCode: 503,
    recoveryTip: 'Layanan sedang dalam pemeliharaan. Silakan coba lagi dalam beberapa saat.',
  },
  [ErrorCode.NOT_IMPLEMENTED]: {
    code: ErrorCode.NOT_IMPLEMENTED,
    message: 'Fitur belum diimplementasikan',
    statusCode: 501,
    recoveryTip: 'Fitur ini belum tersedia. Silakan coba fitur lain atau hubungi support.',
  },

  // Business Logic Errors
  [ErrorCode.BUSINESS_LOGIC_ERROR]: {
    code: ErrorCode.BUSINESS_LOGIC_ERROR,
    message: 'Terjadi kesalahan pada logika bisnis',
    statusCode: 400,
    recoveryTip: 'Operasi tidak dapat diselesaikan karena melanggar aturan bisnis. Silakan periksa kembali data Anda.',
  },
  [ErrorCode.INVALID_STATE]: {
    code: ErrorCode.INVALID_STATE,
