  },
  [ErrorCode.OPERATION_NOT_ALLOWED]: {
    code: ErrorCode.OPERATION_NOT_ALLOWED,
    message: 'Operasi tidak diizinkan',
    statusCode: 403,
    recoveryTip: 'Operasi ini tidak diizinkan dalam konteks saat ini. Hubungi administrator jika Anda merasa ini adalah kesalahan.',
  },
};

/**
 * Get error definition by code
 */
export function getErrorDefinition(code: ErrorCode): ErrorDefinition {
  return ERROR_DEFINITIONS[code] || ERROR_DEFINITIONS[ErrorCode.INTERNAL_SERVER_ERROR];
}

/**
 * Get HTTP status code by error code
 */
export function getStatusCode(code: ErrorCode): number {
  return getErrorDefinition(code).statusCode;
}

/**
 * Get error message by code
 */
export function getErrorMessage(code: ErrorCode): string {
  return getErrorDefinition(code).message;
}

/**
 * Get recovery tip by code
 */
export function getRecoveryTip(code: ErrorCode): string {
  return getErrorDefinition(code).recoveryTip;
}

/**
 * Logger Service
 * Comprehensive structured logging with file rotation, performance metrics, and request tracking
 */

import fs from 'fs';
import path from 'path';
import { createWriteStream, WriteStream } from 'fs';

export enum LogLevel {
  DEBUG = 'DEBUG',
  INFO = 'INFO',
  WARN = 'WARN',
  ERROR = 'ERROR',
  FATAL = 'FATAL',
}

export interface LogContext {
  requestId?: string;
  userId?: string;
  userRole?: string;
  ipAddress?: string;
  method?: string;
  path?: string;
  statusCode?: number;
  duration?: number;
  [key: string]: any;
}

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  context?: LogContext;
  error?: {
    name: string;
    message: string;
    stack?: string;
    code?: string;
  };
  metrics?: {
    duration?: number;
    memoryUsage?: NodeJS.MemoryUsage;
    [key: string]: any;
  };
}

export class LoggerService {
  private logDir: string;
  private currentLogFile: string;
  private writeStream: WriteStream | null = null;
  private logLevel: LogLevel = LogLevel.INFO;
  private maxLogSize: number = 10 * 1024 * 1024; // 10MB
  private maxLogDays: number = 30;
  private requestIdMap: Map<string, string> = new Map();

  constructor(logDir: string = 'logs', logLevel: LogLevel = LogLevel.INFO) {
    this.logDir = logDir;
    this.logLevel = logLevel;
    this.currentLogFile = this.getLogFilePath();
    this.initializeLogDirectory();
    this.initializeWriteStream();
    this.startLogRotationSchedule();
  }

  /**
   * Initialize log directory
   */
  private initializeLogDirectory(): void {
    if (!fs.existsSync(this.logDir)) {
      fs.mkdirSync(this.logDir, { recursive: true });
    }
  }

  /**
   * Initialize write stream for file logging
   */
  private initializeWriteStream(): void {
    try {
      this.writeStream = createWriteStream(this.currentLogFile, { flags: 'a' });
      this.writeStream.on('error', (err) => {
        console.error('[LoggerService] Write stream error:', err);
      });
    } catch (err) {
      console.error('[LoggerService] Failed to initialize write stream:', err);
    }
  }

  /**
   * Get log file path for today
   */
  private getLogFilePath(): string {
    const date = new Date();
    const dateStr = date.toISOString().split('T')[0];
    return path.join(this.logDir, `app-${dateStr}.log`);
  }

  /**
   * Check if log rotation is needed
   */
  private shouldRotate(): boolean {
    const newLogFile = this.getLogFilePath();
    if (newLogFile !== this.currentLogFile) {
      return true;
    }

    try {
      const stats = fs.statSync(this.currentLogFile);
      return stats.size > this.maxLogSize;
    } catch {
      return false;
    }
  }

  /**
   * Rotate log file
   */
  private rotateLog(): void {
    try {
      if (this.writeStream) {
        this.writeStream.end();
        this.writeStream = null;
      }

      const newLogFile = this.getLogFilePath();
      if (newLogFile !== this.currentLogFile) {
        this.currentLogFile = newLogFile;
      } else {
        // Same day but file too large - add timestamp
        const timestamp = new Date().getTime();
        this.currentLogFile = path.join(
          this.logDir,
          `app-${new Date().toISOString().split('T')[0]}-${timestamp}.log`
        );
      }

      this.initializeWriteStream();
      this.cleanOldLogs();
    } catch (err) {
      console.error('[LoggerService] Log rotation failed:', err);
    }
  }

  /**
   * Clean logs older than maxLogDays
   */
  private cleanOldLogs(): void {
    try {
      const files = fs.readdirSync(this.logDir);
      const now = Date.now();
      const maxAge = this.maxLogDays * 24 * 60 * 60 * 1000;

      files.forEach((file) => {
        const filePath = path.join(this.logDir, file);
        const stats = fs.statSync(filePath);
        if (now - stats.mtime.getTime() > maxAge) {
          fs.unlinkSync(filePath);
        }
      });
    } catch (err) {
      console.error('[LoggerService] Failed to clean old logs:', err);
    }
  }

  /**
   * Start log rotation schedule (check every hour)
   */
  private startLogRotationSchedule(): void {
    setInterval(() => {
      if (this.shouldRotate()) {
        this.rotateLog();
      }
    }, 60 * 60 * 1000); // Every hour
  }

  /**
   * Check if log level should be logged
   */
  private shouldLog(level: LogLevel): boolean {
    const levels = [LogLevel.DEBUG, LogLevel.INFO, LogLevel.WARN, LogLevel.ERROR, LogLevel.FATAL];
    const currentIndex = levels.indexOf(this.logLevel);
    const messageIndex = levels.indexOf(level);
    return messageIndex >= currentIndex;
  }

  /**
   * Format log entry as JSON
   */
  private formatLogEntry(entry: LogEntry): string {
    return JSON.stringify(entry) + '\n';
  }

  /**
   * Write log to file and console
   */
  private writeLog(entry: LogEntry): void {
    if (!this.shouldLog(entry.level)) {
      return;
    }

    // Check for rotation
    if (this.shouldRotate()) {
      this.rotateLog();
    }

    const formatted = this.formatLogEntry(entry);

    // Write to file
    if (this.writeStream && !this.writeStream.destroyed) {
      this.writeStream.write(formatted);
    }

    // Write to console
    this.logToConsole(entry);
  }

  /**
   * Log to console with color coding
   */
  private logToConsole(entry: LogEntry): void {
    const colors = {
      [LogLevel.DEBUG]: '\x1b[36m', // Cyan
      [LogLevel.INFO]: '\x1b[32m', // Green
      [LogLevel.WARN]: '\x1b[33m', // Yellow
      [LogLevel.ERROR]: '\x1b[31m', // Red
      [LogLevel.FATAL]: '\x1b[35m', // Magenta
    };
    const reset = '\x1b[0m';
    const color = colors[entry.level];

    const logMessage = `${color}[${entry.timestamp}] [${entry.level}]${reset} ${entry.message}`;

    if (entry.level === LogLevel.ERROR || entry.level === LogLevel.FATAL) {
      console.error(logMessage, entry.error || entry.context || '');
    } else if (entry.level === LogLevel.WARN) {
      console.warn(logMessage, entry.context || '');
    } else {
      console.log(logMessage, entry.context || '');
    }
  }

  /**
   * Generate request ID
   */
  public generateRequestId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  /**
   * Set request ID for tracking
   */
  public setRequestId(requestId: string): void {
    this.requestIdMap.set(requestId, requestId);
  }

  /**
   * Get request ID
   */
  public getRequestId(key?: string): string | undefined {
    if (key) {
      return this.requestIdMap.get(key);
    }
    return undefined;
  }

  /**
   * Log debug message
   */
  public debug(message: string, context?: LogContext): void {
    this.writeLog({
      timestamp: new Date().toISOString(),
      level: LogLevel.DEBUG,
      message,
      context,
    });
  }

  /**
   * Log info message
   */
  public info(message: string, context?: LogContext): void {
    this.writeLog({
      timestamp: new Date().toISOString(),
      level: LogLevel.INFO,
      message,
      context,
    });
  }

  /**
   * Log warning message
   */
  public warn(message: string, context?: LogContext): void {
    this.writeLog({
      timestamp: new Date().toISOString(),
      level: LogLevel.WARN,
      message,
      context,
    });
  }

  /**
   * Log error message
   */
  public error(message: string, error?: Error | any, context?: LogContext): void {
    const errorObj = error instanceof Error ? error : new Error(String(error));
    this.writeLog({
      timestamp: new Date().toISOString(),
      level: LogLevel.ERROR,
      message,
      error: {
        name: errorObj.name,
        message: errorObj.message,
        stack: errorObj.stack,
        code: (errorObj as any).code,
      },
      context,
    });
  }

  /**
   * Log fatal error
   */
  public fatal(message: string, error?: Error | any, context?: LogContext): void {
    const errorObj = error instanceof Error ? error : new Error(String(error));
    this.writeLog({
      timestamp: new Date().toISOString(),
      level: LogLevel.FATAL,
      message,
      error: {
        name: errorObj.name,
        message: errorObj.message,
        stack: errorObj.stack,
        code: (errorObj as any).code,
      },
      context,
    });
  }

  /**
   * Log with performance metrics
   */
  public logWithMetrics(
    message: string,
    level: LogLevel = LogLevel.INFO,
    metrics?: { duration?: number; [key: string]: any },
    context?: LogContext
  ): void {
    this.writeLog({
      timestamp: new Date().toISOString(),
      level,
      message,
      context,
      metrics: {
        ...metrics,
        memoryUsage: process.memoryUsage(),
      },
    });
  }

  /**
   * Close logger and flush streams
   */
  public close(): Promise<void> {
    return new Promise((resolve) => {
      if (this.writeStream) {
        this.writeStream.end(() => {
          resolve();
        });
      } else {
        resolve();
      }
    });
  }

  /**
   * Set log level
   */
  public setLogLevel(level: LogLevel): void {
    this.logLevel = level;
  }

  /**
   * Get current log level
   */
  public getLogLevel(): LogLevel {
    return this.logLevel;
  }
}

// Singleton instance
let loggerInstance: LoggerService | null = null;

/**
 * Get or create logger instance
 */
export function getLogger(logDir?: string, logLevel?: LogLevel): LoggerService {
  if (!loggerInstance) {
    loggerInstance = new LoggerService(logDir, logLevel);
  }
  return loggerInstance;
}

/**
 * Export singleton
 */
export const logger = getLogger();

/**
 * Error Handler Middleware
 * Centralized error handling with logging, error code mapping, and user-friendly responses
 */

import { FastifyRequest, FastifyReply, FastifyError } from 'fastify';
import { logger } from '../services/loggerService';
import { ErrorCode, getErrorDefinition, ERROR_DEFINITIONS } from '../constants/errorCodes';

export interface AppError extends Error {
  statusCode?: number;
  code?: ErrorCode;
  context?: Record<string, any>;
}

/**
 * Create app error
 */
export function createAppError(
  message: string,
  code: ErrorCode = ErrorCode.INTERNAL_SERVER_ERROR,
  statusCode?: number,
  context?: Record<string, any>
): AppError {
  const error = new Error(message) as AppError;
  error.code = code;
  error.statusCode = statusCode || getErrorDefinition(code).statusCode;
  error.context = context;
  return error;
}

/**
 * Error handler middleware
 */
export async function errorHandler(
  error: FastifyError | AppError | Error,
  request: FastifyRequest,
  reply: FastifyReply
): Promise<void> {
  const requestId = request.id || 'unknown';
  const userId = (request.user as any)?.id || 'anonymous';
  const userRole = (request.user as any)?.role || 'guest';

  // Extract error information
  let errorCode: ErrorCode = ErrorCode.INTERNAL_SERVER_ERROR;
  let statusCode: number = 500;
  let message: string = 'Terjadi kesalahan pada server';
  let context: Record<string, any> = {};

  // Handle AppError
  if ((error as AppError).code) {
    const appError = error as AppError;
    errorCode = appError.code;
    statusCode = appError.statusCode || getErrorDefinition(errorCode).statusCode;
    message = appError.message;
    context = appError.context || {};
  }
  // Handle Fastify validation errors
  else if ((error as FastifyError).validation) {
    errorCode = ErrorCode.VALIDATION_FAILED;
    statusCode = 400;
    message = 'Validasi data gagal';
    context = {
      validation: (error as FastifyError).validation,
    };
  }
  // Handle standard errors
  else {
    statusCode = (error as any).statusCode || 500;
    message = error.message || 'Terjadi kesalahan pada server';
  }

  // Ensure statusCode is valid
  if (statusCode < 100 || statusCode > 599) {
    statusCode = 500;
  }

  // Log error with context
  const logContext = {
    requestId,
    userId,
    userRole,
    method: request.method,
    path: request.url,
    statusCode,
    ipAddress: request.ip,
    ...context,
  };

  if (statusCode >= 500) {
    logger.error(`[${errorCode}] ${message}`, error, logContext);
  } else if (statusCode >= 400) {
    logger.warn(`[${errorCode}] ${message}`, logContext);
  } else {
    logger.info(`[${errorCode}] ${message}`, logContext);
  }

  // Get error definition for recovery tip
  const errorDef = ERROR_DEFINITIONS[errorCode] || ERROR_DEFINITIONS[ErrorCode.INTERNAL_SERVER_ERROR];

  // Build response
  const response = {
    success: false,
    error: {
      code: errorCode,
      message: errorDef.message,
      recoveryTip: errorDef.recoveryTip,
      requestId,
      timestamp: new Date().toISOString(),
    },
    ...(process.env.NODE_ENV === 'development' && {
      debug: {
        originalMessage: message,
        stack: error.stack,
        context,
      },
    }),
  };

  // Send response
  reply.status(statusCode).send(response);
}

/**
 * Async error wrapper for route handlers
 */
export function asyncHandler(fn: (req: FastifyRequest, reply: FastifyReply) => Promise<any>) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      return await fn(request, reply);
    } catch (error) {
      throw error;
    }
  };
}

/**
 * Validation error handler
 */
export function handleValidationError(
  errors: any[],
  context?: Record<string, any>
): AppError {
  const firstError = errors[0];
  const message = firstError?.message || 'Validasi data gagal';

  return createAppError(
    message,
    ErrorCode.VALIDATION_FAILED,
    400,
    {
      errors,
      ...context,
    }
  );
}

/**
 * Database error handler
 */
export function handleDatabaseError(error: any, context?: Record<string, any>): AppError {
  logger.error('Database error', error, context);

  // Handle specific Prisma errors
  if (error.code === 'P2002') {
    return createAppError(
      'Data sudah ada',
      ErrorCode.RESOURCE_ALREADY_EXISTS,
      409,
      { field: error.meta?.target, ...context }
    );
  }

  if (error.code === 'P2025') {
    return createAppError(
      'Resource tidak ditemukan',
      ErrorCode.RESOURCE_NOT_FOUND,
      404,
      context
    );
  }

  if (error.code === 'P2003') {
    return createAppError(
      'Foreign key constraint failed',
      ErrorCode.DATABASE_ERROR,
      400,
      { field: error.meta?.field_name, ...context }
    );
  }

  return createAppError(
    'Terjadi kesalahan pada database',
    ErrorCode.DATABASE_ERROR,
    500,
    context
  );
}

/**
 * External service error handler
 */
export function handleExternalServiceError(
  error: any,
  serviceName: string,
  context?: Record<string, any>
): AppError {
  logger.error(`External service error: ${serviceName}`, error, context);

  if (error.code === 'ECONNREFUSED' || error.code === 'ENOTFOUND') {
    return createAppError(
      `${serviceName} tidak tersedia`,
      ErrorCode.EXTERNAL_SERVICE_UNAVAILABLE,
      503,
      { service: serviceName, ...context }
    );
  }

  if (error.code === 'ETIMEDOUT' || error.code === 'ESOCKETTIMEDOUT') {
    return createAppError(
      `${serviceName} timeout`,
      ErrorCode.EXTERNAL_SERVICE_TIMEOUT,
      504,
      { service: serviceName, ...context }
    );
  }

  return createAppError(
    `${serviceName} mengalami kesalahan`,
    ErrorCode.EXTERNAL_SERVICE_ERROR,
    502,
    { service: serviceName, ...context }
  );
}

/**
 * File upload error handler
 */
export function handleFileUploadError(error: any, context?: Record<string, any>): AppError {
  logger.error('File upload error', error, context);

  if (error.code === 'FST_PARTS_LIMIT') {
    return createAppError(
      'File terlalu besar',
      ErrorCode.FILE_TOO_LARGE,
      413,
      context
    );
  }

  if (error.code === 'FST_REQ_FILE_TOO_LARGE') {
    return createAppError(
      'File terlalu besar',
      ErrorCode.FILE_TOO_LARGE,
      413,
      context
    );
  }

  return createAppError(
    'Upload file gagal',
    ErrorCode.FILE_UPLOAD_FAILED,
    400,
    context
  );
}

