/**
 * Error Handler Tests
 * Unit tests for error handling, error code mapping, and error responses
 */

import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  createAppError,
  handleValidationError,
  handleDatabaseError,
  handleExternalServiceError,
  handleFileUploadError,
  handleAuthError,
  handleAuthorizationError,
  handleRateLimitError,
  handleBusinessLogicError,
  handleNotFoundError,
  handleConflictError,
} from '../middleware/errorHandler';
import { ErrorCode, getErrorDefinition } from '../constants/errorCodes';

describe('Error Handler', () => {
  describe('createAppError', () => {
    it('should create app error with default code', () => {
      const error = createAppError('Test error');
      expect(error.message).toBe('Test error');
      expect(error.code).toBe(ErrorCode.INTERNAL_SERVER_ERROR);
      expect(error.statusCode).toBe(500);
    });

    it('should create app error with custom code', () => {
      const error = createAppError('Not found', ErrorCode.RESOURCE_NOT_FOUND);
      expect(error.message).toBe('Not found');
      expect(error.code).toBe(ErrorCode.RESOURCE_NOT_FOUND);
      expect(error.statusCode).toBe(404);
    });

    it('should create app error with custom status code', () => {
      const error = createAppError('Custom error', ErrorCode.BUSINESS_LOGIC_ERROR, 422);
      expect(error.statusCode).toBe(422);
    });

    it('should create app error with context', () => {
      const context = { userId: 'user123', action: 'DELETE' };
      const error = createAppError('Error with context', ErrorCode.OPERATION_NOT_ALLOWED, undefined, context);
      expect(error.context).toEqual(context);
    });

    it('should use error definition status code when not provided', () => {
      const error = createAppError('Auth error', ErrorCode.AUTH_UNAUTHORIZED);
      const definition = getErrorDefinition(ErrorCode.AUTH_UNAUTHORIZED);
      expect(error.statusCode).toBe(definition.statusCode);
    });
  });

  describe('Validation Error Handler', () => {
    it('should handle validation errors', () => {
      const errors = [
        { message: 'Email is required', path: ['email'] },
        { message: 'Password must be at least 6 characters', path: ['password'] },
      ];
      const error = handleValidationError(errors);

      expect(error.code).toBe(ErrorCode.VALIDATION_FAILED);
      expect(error.statusCode).toBe(400);
      expect(error.context?.errors).toEqual(errors);
    });

    it('should use first error message', () => {
      const errors = [
        { message: 'First error' },
        { message: 'Second error' },
      ];
      const error = handleValidationError(errors);
      expect(error.message).toBe('First error');
    });

    it('should handle empty errors array', () => {
      const error = handleValidationError([]);
      expect(error.message).toBe('Validasi data gagal');
    });

    it('should include context in error', () => {
      const errors = [{ message: 'Error' }];
      const context = { field: 'email' };
      const error = handleValidationError(errors, context);
      expect(error.context?.field).toBe('email');
    });
  });

  describe('Database Error Handler', () => {
    it('should handle P2002 (unique constraint) error', () => {
      const dbError = {
        code: 'P2002',
        meta: { target: ['email'] },
      };
      const error = handleDatabaseError(dbError);

      expect(error.code).toBe(ErrorCode.RESOURCE_ALREADY_EXISTS);
      expect(error.statusCode).toBe(409);
      expect(error.message).toBe('Data sudah ada');
    });

    it('should handle P2025 (not found) error', () => {
      const dbError = { code: 'P2025' };
      const error = handleDatabaseError(dbError);

      expect(error.code).toBe(ErrorCode.RESOURCE_NOT_FOUND);
      expect(error.statusCode).toBe(404);
    });

    it('should handle P2003 (foreign key) error', () => {
      const dbError = {
        code: 'P2003',
        meta: { field_name: 'userId' },
      };
      const error = handleDatabaseError(dbError);

      expect(error.code).toBe(ErrorCode.DATABASE_ERROR);
      expect(error.statusCode).toBe(400);
      expect(error.context?.field).toBe('userId');
    });

    it('should handle generic database error', () => {
      const dbError = new Error('Database connection failed');
      const error = handleDatabaseError(dbError);

      expect(error.code).toBe(ErrorCode.DATABASE_ERROR);
      expect(error.statusCode).toBe(500);
    });

    it('should include context in error', () => {
      const dbError = { code: 'P2025' };
      const context = { table: 'users' };
      const error = handleDatabaseError(dbError, context);
      expect(error.context?.table).toBe('users');
    });
  });

  describe('External Service Error Handler', () => {
    it('should handle connection refused error', () => {
      const serviceError = { code: 'ECONNREFUSED' };
      const error = handleExternalServiceError(serviceError, 'PaymentService');

      expect(error.code).toBe(ErrorCode.EXTERNAL_SERVICE_UNAVAILABLE);
      expect(error.statusCode).toBe(503);
      expect(error.message).toContain('PaymentService');
    });

    it('should handle not found error', () => {
      const serviceError = { code: 'ENOTFOUND' };
      const error = handleExternalServiceError(serviceError, 'EmailService');

      expect(error.code).toBe(ErrorCode.EXTERNAL_SERVICE_UNAVAILABLE);
      expect(error.statusCode).toBe(503);
    });

    it('should handle timeout error', () => {
      const serviceError = { code: 'ETIMEDOUT' };
      const error = handleExternalServiceError(serviceError, 'APIService');

      expect(error.code).toBe(ErrorCode.EXTERNAL_SERVICE_TIMEOUT);
      expect(error.statusCode).toBe(504);
    });

    it('should handle socket timeout error', () => {
      const serviceError = { code: 'ESOCKETTIMEDOUT' };
      const error = handleExternalServiceError(serviceError, 'DatabaseService');

      expect(error.code).toBe(ErrorCode.EXTERNAL_SERVICE_TIMEOUT);
      expect(error.statusCode).toBe(504);
    });

    it('should handle generic external service error', () => {
      const serviceError = new Error('Service error');
      const error = handleExternalServiceError(serviceError, 'UnknownService');

      expect(error.code).toBe(ErrorCode.EXTERNAL_SERVICE_ERROR);
      expect(error.statusCode).toBe(502);
    });

    it('should include service name in context', () => {
      const serviceError = { code: 'ECONNREFUSED' };
      const error = handleExternalServiceError(serviceError, 'TestService');
      expect(error.context?.service).toBe('TestService');
    });
  });

  describe('File Upload Error Handler', () => {
    it('should handle file size limit error', () => {
      const uploadError = { code: 'FST_PARTS_LIMIT' };
      const error = handleFileUploadError(uploadError);

      expect(error.code).toBe(ErrorCode.FILE_TOO_LARGE);
      expect(error.statusCode).toBe(413);
    });

    it('should handle request file too large error', () => {
      const uploadError = { code: 'FST_REQ_FILE_TOO_LARGE' };
      const error = handleFileUploadError(uploadError);

      expect(error.code).toBe(ErrorCode.FILE_TOO_LARGE);
      expect(error.statusCode).toBe(413);
    });

    it('should handle generic file upload error', () => {
      const uploadError = new Error('Upload failed');
      const error = handleFileUploadError(uploadError);

      expect(error.code).toBe(ErrorCode.FILE_UPLOAD_FAILED);
      expect(error.statusCode).toBe(400);
    });

    it('should include context in error', () => {
      const uploadError = { code: 'FST_PARTS_LIMIT' };
      const context = { filename: 'large-file.zip' };
      const error = handleFileUploadError(uploadError, context);
      expect(error.context?.filename).toBe('large-file.zip');
    });
  });

  describe('Authentication Error Handler', () => {
    it('should create auth error with default code', () => {
      const error = handleAuthError('Invalid credentials');

      expect(error.code).toBe(ErrorCode.AUTH_UNAUTHORIZED);
      expect(error.statusCode).toBe(401);
      expect(error.message).toBe('Invalid credentials');
    });

    it('should create auth error with custom code', () => {
      const error = handleAuthError('Email already exists', ErrorCode.AUTH_EMAIL_EXISTS);

      expect(error.code).toBe(ErrorCode.AUTH_EMAIL_EXISTS);
      expect(error.statusCode).toBe(409);
    });

    it('should include context in error', () => {
      const context = { email: 'test@example.com' };
      const error = handleAuthError('Email exists', ErrorCode.AUTH_EMAIL_EXISTS, context);
      expect(error.context?.email).toBe('test@example.com');
    });
  });

  describe('Authorization Error Handler', () => {
    it('should create authorization error', () => {
      const error = handleAuthorizationError();

      expect(error.code).toBe(ErrorCode.AUTH_FORBIDDEN);
      expect(error.statusCode).toBe(403);
    });

    it('should include context in error', () => {
      const context = { requiredRole: 'admin' };
      const error = handleAuthorizationError(context);
      expect(error.context?.requiredRole).toBe('admin');
    });
  });

  describe('Rate Limit Error Handler', () => {
    it('should create rate limit error', () => {
      const error = handleRateLimitError();

      expect(error.code).toBe(ErrorCode.RATE_LIMIT_EXCEEDED);
      expect(error.statusCode).toBe(429);
    });

    it('should include context in error', () => {
      const context = { retryAfter: 60 };
      const error = handleRateLimitError(context);
      expect(error.context?.retryAfter).toBe(60);
    });
  });

  describe('Business Logic Error Handler', () => {
    it('should create business logic error', () => {
      const error = handleBusinessLogicError('Cannot delete active user');

      expect(error.code).toBe(ErrorCode.BUSINESS_LOGIC_ERROR);
      expect(error.statusCode).toBe(400);
      expect(error.message).toBe('Cannot delete active user');
    });

    it('should include context in error', () => {
      const context = { userId: 'user123', status: 'ACTIVE' };
      const error = handleBusinessLogicError('Cannot delete', context);
      expect(error.context?.userId).toBe('user123');
    });
  });

  describe('Not Found Error Handler', () => {
    it('should create not found error with default resource', () => {
      const error = handleNotFoundError();

      expect(error.code).toBe(ErrorCode.RESOURCE_NOT_FOUND);
      expect(error.statusCode).toBe(404);
      expect(error.message).toContain('Resource');
    });

    it('should create not found error with custom resource', () => {
      const error = handleNotFoundError('User');

      expect(error.message).toContain('User');
    });

    it('should include context in error', () => {
      const context = { id: 'user123' };
      const error = handleNotFoundError('User', context);
      expect(error.context?.id).toBe('user123');
    });
  });

  describe('Conflict Error Handler', () => {
    it('should create conflict error with default message', () => {
      const error = handleConflictError();

      expect(error.code).toBe(ErrorCode.RESOURCE_CONFLICT);
      expect(error.statusCode).toBe(409);
    });

    it('should create conflict error with custom message', () => {
      const error = handleConflictError('Username already taken');

      expect(error.message).toBe('Username already taken');
    });

    it('should include context in error', () => {
      const context = { field: 'username' };
      const error = handleConflictError('Conflict', context);
      expect(error.context?.field).toBe('username');
    });
  });

  describe('Error Code Definitions', () => {
    it('should have valid status codes for all error codes', () => {
      const errorCodes = Object.values(ErrorCode);
      errorCodes.forEach((code) => {
        const definition = getErrorDefinition(code as ErrorCode);
        expect(definition.statusCode).toBeGreaterThanOrEqual(100);
        expect(definition.statusCode).toBeLessThan(600);
      });
    });

    it('should have messages for all error codes', () => {
      const errorCodes = Object.values(ErrorCode);
      errorCodes.forEach((code) => {
        const definition = getErrorDefinition(code as ErrorCode);
        expect(definition.message).toBeTruthy();
        expect(definition.message.length).toBeGreaterThan(0);
      });
    });

    it('should have recovery tips for all error codes', () => {
      const errorCodes = Object.values(ErrorCode);
      errorCodes.forEach((code) => {
        const definition = getErrorDefinition(code as ErrorCode);
        expect(definition.recoveryTip).toBeTruthy();
        expect(definition.recoveryTip.length).toBeGreaterThan(0);
      });
    });
  });

  describe('Error Status Code Mapping', () => {
    it('should map 4xx errors correctly', () => {
      expect(getErrorDefinition(ErrorCode.VALIDATION_FAILED).statusCode).toBe(400);
      expect(getErrorDefinition(ErrorCode.AUTH_UNAUTHORIZED).statusCode).toBe(401);
      expect(getErrorDefinition(ErrorCode.AUTH_FORBIDDEN).statusCode).toBe(403);
      expect(getErrorDefinition(ErrorCode.RESOURCE_NOT_FOUND).statusCode).toBe(404);
      expect(getErrorDefinition(ErrorCode.RESOURCE_ALREADY_EXISTS).statusCode).toBe(409);
    });

    it('should map 5xx errors correctly', () => {
      expect(getErrorDefinition(ErrorCode.INTERNAL_SERVER_ERROR).statusCode).toBe(500);
      expect(getErrorDefinition(ErrorCode.DATABASE_ERROR).statusCode).toBe(500);
      expect(getErrorDefinition(ErrorCode.SERVICE_UNAVAILABLE).statusCode).toBe(503);
    });

    it('should map 3xx errors correctly', () => {
      expect(getErrorDefinition(ErrorCode.RESOURCE_DELETED).statusCode).toBe(410);
    });
  });

  describe('Error Context Preservation', () => {
    it('should preserve context through error creation', () => {
      const originalContext = {
        userId: 'user123',
        action: 'DELETE',
        timestamp: new Date().toISOString(),
      };

      const error = createAppError(
        'Test error',
        ErrorCode.OPERATION_NOT_ALLOWED,
        undefined,
        originalContext
      );

      expect(error.context).toEqual(originalContext);
    });

    it('should merge context in error handlers', () => {
      const baseContext = { userId: 'user123' };
      const error = handleDatabaseError(
        { code: 'P2025' },
        baseContext
      );

      expect(error.context?.userId).toBe('user123');
    });
  });
});

